import os
import numpy as np

working_dir = os.path.join(os.getcwd(), "working")
experiment_path = os.path.join(working_dir, "experiment_data.npy")

experiment_data = np.load(experiment_path, allow_pickle=True).item()

if not isinstance(experiment_data, dict) or len(experiment_data) == 0:
    raise ValueError(f"Unexpected experiment data format in: {experiment_path}")

ablation_type = next(iter(experiment_data.keys()))
dataset_dict = experiment_data[ablation_type]


def to_python_scalar(x):
    if isinstance(x, np.generic):
        return x.item()
    return x


def fmt_value(x):
    x = to_python_scalar(x)
    if isinstance(x, float):
        return f"{x:.6f}"
    return str(x)


def parse_train_metrics(train_entries):
    # Stored as (epoch, tr_acc, tr_acc)
    parsed = []
    for row in train_entries:
        epoch, train_accuracy, train_srus_proxy = row
        parsed.append(
            {
                "epoch": int(to_python_scalar(epoch)),
                "train_accuracy": float(to_python_scalar(train_accuracy)),
                "train_srus_proxy": float(to_python_scalar(train_srus_proxy)),
            }
        )
    return parsed


def parse_val_metrics(val_entries):
    # Stored as (epoch, va_acc, val_srus)
    parsed = []
    for row in val_entries:
        epoch, validation_accuracy, validation_srus = row
        parsed.append(
            {
                "epoch": int(to_python_scalar(epoch)),
                "validation_accuracy": float(to_python_scalar(validation_accuracy)),
                "validation_srus": float(to_python_scalar(validation_srus)),
            }
        )
    return parsed


def parse_loss_entries(loss_entries, loss_name):
    # Stored as (epoch, loss)
    parsed = []
    for row in loss_entries:
        epoch, loss_value = row
        parsed.append(
            {
                "epoch": int(to_python_scalar(epoch)),
                loss_name: float(to_python_scalar(loss_value)),
            }
        )
    return parsed


def parse_test_metrics(test_entries):
    # Stored as:
    # (gate_type, acc, ece, trigger_rate, update_rate, overhead, srus)
    parsed = []
    for row in test_entries:
        gate_type, accuracy, ece, trigger_rate, update_rate, overhead, srus = row
        parsed.append(
            {
                "gate_variant": str(gate_type),
                "test_accuracy": float(to_python_scalar(accuracy)),
                "test_ece": float(to_python_scalar(ece)),
                "test_trigger_rate": float(to_python_scalar(trigger_rate)),
                "test_update_rate": float(to_python_scalar(update_rate)),
                "test_overhead": float(to_python_scalar(overhead)),
                "test_srus": float(to_python_scalar(srus)),
            }
        )
    return parsed


def best_by_key(rows, key, higher_is_better=True):
    if not rows:
        return None
    return (
        max(rows, key=lambda r: r[key])
        if higher_is_better
        else min(rows, key=lambda r: r[key])
    )


for dataset_name, dataset_payload in dataset_dict.items():
    print(f"Dataset: {dataset_name}")

    metrics = dataset_payload.get("metrics", {})
    losses = dataset_payload.get("losses", {})

    train_metrics = parse_train_metrics(metrics.get("train", []))
    val_metrics = parse_val_metrics(metrics.get("val", []))
    test_metrics = parse_test_metrics(metrics.get("test", []))

    train_losses = parse_loss_entries(losses.get("train", []), "train_loss")
    val_losses = parse_loss_entries(losses.get("val", []), "validation_loss")

    if train_metrics:
        final_train = train_metrics[-1]
        best_train_accuracy = best_by_key(
            train_metrics, "train_accuracy", higher_is_better=True
        )
        best_train_srus_proxy = best_by_key(
            train_metrics, "train_srus_proxy", higher_is_better=True
        )

        print(
            f"  Final train accuracy: {fmt_value(final_train['train_accuracy'])} (epoch {final_train['epoch']})"
        )
        print(
            f"  Best train accuracy: {fmt_value(best_train_accuracy['train_accuracy'])} (epoch {best_train_accuracy['epoch']})"
        )
        print(
            f"  Final train SRUS proxy: {fmt_value(final_train['train_srus_proxy'])} (epoch {final_train['epoch']})"
        )
        print(
            f"  Best train SRUS proxy: {fmt_value(best_train_srus_proxy['train_srus_proxy'])} (epoch {best_train_srus_proxy['epoch']})"
        )

    if val_metrics:
        final_val = val_metrics[-1]
        best_val_accuracy = best_by_key(
            val_metrics, "validation_accuracy", higher_is_better=True
        )
        best_val_srus = best_by_key(
            val_metrics, "validation_srus", higher_is_better=True
        )

        print(
            f"  Final validation accuracy: {fmt_value(final_val['validation_accuracy'])} (epoch {final_val['epoch']})"
        )
        print(
            f"  Best validation accuracy: {fmt_value(best_val_accuracy['validation_accuracy'])} (epoch {best_val_accuracy['epoch']})"
        )
        print(
            f"  Final validation SRUS: {fmt_value(final_val['validation_srus'])} (epoch {final_val['epoch']})"
        )
        print(
            f"  Best validation SRUS: {fmt_value(best_val_srus['validation_srus'])} (epoch {best_val_srus['epoch']})"
        )

    if train_losses:
        final_train_loss = train_losses[-1]
        best_train_loss = best_by_key(
            train_losses, "train_loss", higher_is_better=False
        )

        print(
            f"  Final training loss: {fmt_value(final_train_loss['train_loss'])} (epoch {final_train_loss['epoch']})"
        )
        print(
            f"  Best training loss: {fmt_value(best_train_loss['train_loss'])} (epoch {best_train_loss['epoch']})"
        )

    if val_losses:
        final_val_loss = val_losses[-1]
        best_val_loss = best_by_key(
            val_losses, "validation_loss", higher_is_better=False
        )

        print(
            f"  Final validation loss: {fmt_value(final_val_loss['validation_loss'])} (epoch {final_val_loss['epoch']})"
        )
        print(
            f"  Best validation loss: {fmt_value(best_val_loss['validation_loss'])} (epoch {best_val_loss['epoch']})"
        )

    if test_metrics:
        best_test_accuracy = best_by_key(
            test_metrics, "test_accuracy", higher_is_better=True
        )
        best_test_ece = best_by_key(test_metrics, "test_ece", higher_is_better=False)
        best_test_trigger_rate = best_by_key(
            test_metrics, "test_trigger_rate", higher_is_better=False
        )
        best_test_update_rate = best_by_key(
            test_metrics, "test_update_rate", higher_is_better=False
        )
        best_test_overhead = best_by_key(
            test_metrics, "test_overhead", higher_is_better=False
        )
        best_test_srus = best_by_key(test_metrics, "test_srus", higher_is_better=True)

        print(
            f"  Best test accuracy: {fmt_value(best_test_accuracy['test_accuracy'])} "
            f"(gate variant: {best_test_accuracy['gate_variant']})"
        )
        print(
            f"  Best test expected calibration error: {fmt_value(best_test_ece['test_ece'])} "
            f"(gate variant: {best_test_ece['gate_variant']})"
        )
        print(
            f"  Lowest test trigger rate: {fmt_value(best_test_trigger_rate['test_trigger_rate'])} "
            f"(gate variant: {best_test_trigger_rate['gate_variant']})"
        )
        print(
            f"  Lowest test update rate: {fmt_value(best_test_update_rate['test_update_rate'])} "
            f"(gate variant: {best_test_update_rate['gate_variant']})"
        )
        print(
            f"  Lowest test overhead: {fmt_value(best_test_overhead['test_overhead'])} "
            f"(gate variant: {best_test_overhead['gate_variant']})"
        )
        print(
            f"  Best test SRUS: {fmt_value(best_test_srus['test_srus'])} "
            f"(gate variant: {best_test_srus['gate_variant']})"
        )

    print()

import os
import numpy as np

working_dir = os.path.join(os.getcwd(), "working")
experiment_data_path = os.path.join(working_dir, "experiment_data.npy")

experiment_data = np.load(experiment_data_path, allow_pickle=True).item()

ablation_key = "temporal_context_buffer_size_ablation"
if ablation_key not in experiment_data:
    raise KeyError(f"Expected key '{ablation_key}' in experiment_data.npy")

ablation_data = experiment_data[ablation_key]


def safe_float(value):
    try:
        return float(value)
    except Exception:
        return value


def summarize_train_metrics(train_entries):
    summary = {}
    if not train_entries:
        return summary

    final_entry = train_entries[-1]
    # Original format: (epoch, tr_acc, tr_acc)
    if len(final_entry) >= 2:
        summary["final train epoch"] = final_entry[0]
        summary["final train accuracy"] = safe_float(final_entry[1])

    # Since the third value duplicates train accuracy in the source code, print it only if distinct
    if len(final_entry) >= 3 and final_entry[2] != final_entry[1]:
        summary["final train auxiliary metric"] = safe_float(final_entry[2])

    best_entry = max(train_entries, key=lambda x: x[1] if len(x) > 1 else float("-inf"))
    if len(best_entry) >= 2:
        summary["best train epoch"] = best_entry[0]
        summary["best train accuracy"] = safe_float(best_entry[1])

    return summary


def summarize_val_metrics(val_entries):
    summary = {}
    if not val_entries:
        return summary

    final_entry = val_entries[-1]
    # Original format: (epoch, va_acc, va_srus, va_ece)
    if len(final_entry) >= 1:
        summary["final validation epoch"] = final_entry[0]
    if len(final_entry) >= 2:
        summary["final validation accuracy"] = safe_float(final_entry[1])
    if len(final_entry) >= 3:
        summary["final validation SRUS"] = safe_float(final_entry[2])
    if len(final_entry) >= 4:
        summary["final validation ECE"] = safe_float(final_entry[3])

    if val_entries and all(len(x) >= 2 for x in val_entries):
        best_acc_entry = max(val_entries, key=lambda x: x[1])
        summary["best validation accuracy epoch"] = best_acc_entry[0]
        summary["best validation accuracy"] = safe_float(best_acc_entry[1])

    if val_entries and all(len(x) >= 3 for x in val_entries):
        best_srus_entry = max(val_entries, key=lambda x: x[2])
        summary["best validation SRUS epoch"] = best_srus_entry[0]
        summary["best validation SRUS"] = safe_float(best_srus_entry[2])

    if val_entries and all(len(x) >= 4 for x in val_entries):
        best_ece_entry = min(val_entries, key=lambda x: x[3])
        summary["best validation ECE epoch"] = best_ece_entry[0]
        summary["best validation ECE"] = safe_float(best_ece_entry[3])

    return summary


def summarize_loss_metrics(loss_entries, split_name):
    summary = {}
    if not loss_entries:
        return summary

    final_entry = loss_entries[-1]
    # Original format: (epoch, loss)
    if len(final_entry) >= 2:
        summary[f"final {split_name} loss epoch"] = final_entry[0]
        summary[f"final {split_name} loss"] = safe_float(final_entry[1])

    best_entry = min(loss_entries, key=lambda x: x[1] if len(x) > 1 else float("inf"))
    if len(best_entry) >= 2:
        summary[f"best {split_name} loss epoch"] = best_entry[0]
        summary[f"best {split_name} loss"] = safe_float(best_entry[1])

    return summary


def summarize_test_metrics(test_entries):
    summary = {}
    if not test_entries:
        return summary

    # Original format:
    # (mode_name, buffer_k, acc, ece, trigger_rate, update_rate, overhead, srus)
    final_entry = test_entries[-1]
    if len(final_entry) >= 1:
        summary["final test configuration"] = final_entry[0]
    if len(final_entry) >= 2:
        summary["final test buffer size"] = final_entry[1]
    if len(final_entry) >= 3:
        summary["final test accuracy"] = safe_float(final_entry[2])
    if len(final_entry) >= 4:
        summary["final test ECE"] = safe_float(final_entry[3])
    if len(final_entry) >= 5:
        summary["final test trigger rate"] = safe_float(final_entry[4])
    if len(final_entry) >= 6:
        summary["final test update rate"] = safe_float(final_entry[5])
    if len(final_entry) >= 7:
        summary["final test overhead"] = safe_float(final_entry[6])
    if len(final_entry) >= 8:
        summary["final test SRUS"] = safe_float(final_entry[7])

    valid_test_entries = [x for x in test_entries if len(x) >= 8]
    if valid_test_entries:
        best_acc_entry = max(valid_test_entries, key=lambda x: x[2])
        summary["best test accuracy configuration"] = best_acc_entry[0]
        summary["best test accuracy buffer size"] = best_acc_entry[1]
        summary["best test accuracy"] = safe_float(best_acc_entry[2])

        best_ece_entry = min(valid_test_entries, key=lambda x: x[3])
        summary["best test ECE configuration"] = best_ece_entry[0]
        summary["best test ECE buffer size"] = best_ece_entry[1]
        summary["best test ECE"] = safe_float(best_ece_entry[3])

        best_srus_entry = max(valid_test_entries, key=lambda x: x[7])
        summary["best test SRUS configuration"] = best_srus_entry[0]
        summary["best test SRUS buffer size"] = best_srus_entry[1]
        summary["best test SRUS"] = safe_float(best_srus_entry[7])

    return summary


for dataset_name, dataset_payload in ablation_data.items():
    print(f"Dataset: {dataset_name}")

    metrics = dataset_payload.get("metrics", {})
    losses = dataset_payload.get("losses", {})

    train_summary = summarize_train_metrics(metrics.get("train", []))
    val_summary = summarize_val_metrics(metrics.get("val", []))
    test_summary = summarize_test_metrics(metrics.get("test", []))
    train_loss_summary = summarize_loss_metrics(losses.get("train", []), "train")
    val_loss_summary = summarize_loss_metrics(losses.get("val", []), "validation")

    ordered_summaries = [
        train_summary,
        train_loss_summary,
        val_summary,
        val_loss_summary,
        test_summary,
    ]

    for summary in ordered_summaries:
        for metric_name, metric_value in summary.items():
            print(f"{metric_name}: {metric_value}")

    print()

import os
import numpy as np

working_dir = os.path.join(os.getcwd(), "working")
file_path = os.path.join(working_dir, "experiment_data.npy")

experiment_data = np.load(file_path, allow_pickle=True).item()


def safe_float(x):
    try:
        return float(x)
    except Exception:
        return x


def format_value(x):
    x = safe_float(x)
    if isinstance(x, float):
        return f"{x:.6f}"
    return str(x)


def get_final_train_metrics(train_metrics):
    # Stored as: (epoch, tr_acc, tr_acc)
    if not train_metrics:
        return None
    epoch, train_accuracy, _ = train_metrics[-1]
    return {
        "final train epoch": epoch,
        "final train accuracy": train_accuracy,
    }


def get_best_validation_metrics(val_metrics):
    # Stored as: (epoch, va_acc, val_srus)
    if not val_metrics:
        return None
    best_by_accuracy = max(val_metrics, key=lambda x: float(x[1]))
    final_epoch, final_val_accuracy, final_val_srus = val_metrics[-1]
    best_epoch, best_val_accuracy, best_val_srus = best_by_accuracy
    return {
        "final validation epoch": final_epoch,
        "final validation accuracy": final_val_accuracy,
        "final validation SRUS proxy": final_val_srus,
        "best validation epoch": best_epoch,
        "best validation accuracy": best_val_accuracy,
        "best validation SRUS proxy at best validation accuracy": best_val_srus,
    }


def get_final_loss(losses, split_name):
    # Stored as: (epoch, loss)
    if not losses:
        return None
    epoch, loss_value = losses[-1]
    return {
        f"final {split_name} epoch": epoch,
        f"final {split_name} loss": loss_value,
    }


def get_best_loss(losses, split_name):
    if not losses:
        return None
    best_epoch, best_loss_value = min(losses, key=lambda x: float(x[1]))
    return {
        f"best {split_name} epoch": best_epoch,
        f"best {split_name} loss": best_loss_value,
    }


def parse_test_metrics(test_metrics):
    # Stored as:
    # (mode, acc, ece, trigger_rate, update_rate, overhead, srus)
    parsed = {}
    for row in test_metrics:
        if len(row) != 7:
            continue
        mode, acc, ece, trigger_rate, update_rate, overhead, srus = row
        parsed[str(mode)] = {
            f"{mode} test accuracy": acc,
            f"{mode} test ECE": ece,
            f"{mode} test trigger rate": trigger_rate,
            f"{mode} test update rate": update_rate,
            f"{mode} test overhead": overhead,
            f"{mode} test SRUS": srus,
        }
    return parsed


def print_metric_block(metric_dict):
    for metric_name, metric_value in metric_dict.items():
        print(f"{metric_name}: {format_value(metric_value)}")


all_dataset_names = set()
for ablation_name, ablation_data in experiment_data.items():
    for dataset_name in ablation_data.keys():
        all_dataset_names.add(dataset_name)

all_dataset_names = sorted(all_dataset_names)

for dataset_name in all_dataset_names:
    print(f"Dataset: {dataset_name}")
    for ablation_name, ablation_data in experiment_data.items():
        if dataset_name not in ablation_data:
            continue

        ds = ablation_data[dataset_name]
        print(f"Ablation: {ablation_name}")

        final_train = get_final_train_metrics(ds.get("metrics", {}).get("train", []))
        if final_train is not None:
            print_metric_block(final_train)

        best_val = get_best_validation_metrics(ds.get("metrics", {}).get("val", []))
        if best_val is not None:
            print_metric_block(best_val)

        final_train_loss = get_final_loss(
            ds.get("losses", {}).get("train", []), "train"
        )
        if final_train_loss is not None:
            print_metric_block(final_train_loss)

        best_train_loss = get_best_loss(ds.get("losses", {}).get("train", []), "train")
        if best_train_loss is not None:
            print_metric_block(best_train_loss)

        final_val_loss = get_final_loss(
            ds.get("losses", {}).get("val", []), "validation"
        )
        if final_val_loss is not None:
            print_metric_block(final_val_loss)

        best_val_loss = get_best_loss(ds.get("losses", {}).get("val", []), "validation")
        if best_val_loss is not None:
            print_metric_block(best_val_loss)

        parsed_test = parse_test_metrics(ds.get("metrics", {}).get("test", []))
        for mode_name in ["frozen", "always", "gated", "reset"]:
            if mode_name in parsed_test:
                print_metric_block(parsed_test[mode_name])

        predictions = ds.get("predictions", [])
        ground_truth = ds.get("ground_truth", [])
        if len(predictions) > 0:
            print(f"final stored prediction count: {len(predictions)}")
        if len(ground_truth) > 0:
            print(f"final stored ground truth count: {len(ground_truth)}")

        print()
